// C# — Stack: Push, Pop, Peek, Reset

public class Stack<T>
{
    private readonly List<T> _items = new List<T>();

    // Push — add element to the top
    public void Push(T item)
    {
        _items.Add(item);
    }

    // Pop — remove and return the top element
    public T Pop()
    {
        if (IsEmpty())
            throw new InvalidOperationException("Stack is empty.");
        T top = _items[_items.Count - 1];
        _items.RemoveAt(_items.Count - 1);
        return top;
    }

    // Peek — return top element without removing it
    public T Peek()
    {
        if (IsEmpty())
            throw new InvalidOperationException("Stack is empty.");
        return _items[_items.Count - 1];
    }

    // Reset — clear all elements
    public void Reset()
    {
        _items.Clear();
    }

    public bool IsEmpty() => _items.Count == 0;
    public int Size() => _items.Count;
}

// Usage
var stack = new Stack<int>();
stack.Push(10);
stack.Push(20);
stack.Push(30);

int top = stack.Peek();  // 30 — not removed
int popped = stack.Pop(); // 30 — removed

stack.Reset(); // stack is now empty

// C++ — Stack: Push, Pop, Peek, Reset
#include <iostream>
#include <vector>
#include <stdexcept>
using namespace std;

template <typename T>
class Stack {
    vector<T> items;
public:
    // Push — add element to top
    void push(T item) {
        items.push_back(item);
    }

    // Pop — remove and return top element
    T pop() {
        if (isEmpty())
            throw runtime_error("Stack is empty.");
        T top = items.back();
        items.pop_back();
        return top;
    }

    // Peek — return top element without removing
    T peek() {
        if (isEmpty())
            throw runtime_error("Stack is empty.");
        return items.back();
    }

    // Reset — clear all elements
    void reset() {
        items.clear();
    }

    bool isEmpty() const { return items.empty(); }
    int size() const { return items.size(); }
};

int main() {
    Stack<int> stack;
    stack.push(10);
    stack.push(20);
    stack.push(30);

    int top = stack.peek();   // 30 — not removed
    int popped = stack.pop(); // 30 — removed

    stack.reset(); // stack is now empty
    return 0;
}

// Java — Stack: Push, Pop, Peek, Reset
import java.util.ArrayList;

public class Stack<T> {
    private final ArrayList<T> items = new ArrayList<>();

    // Push — add element to top
    public void push(T item) {
        items.add(item);
    }

    // Pop — remove and return top element
    public T pop() {
        if (isEmpty())
            throw new RuntimeException("Stack is empty.");
        return items.remove(items.size() - 1);
    }

    // Peek — return top element without removing
    public T peek() {
        if (isEmpty())
            throw new RuntimeException("Stack is empty.");
        return items.get(items.size() - 1);
    }

    // Reset — clear all elements
    public void reset() {
        items.clear();
    }

    public boolean isEmpty() { return items.isEmpty(); }
    public int size() { return items.size(); }

    public static void main(String[] args) {
        Stack<Integer> stack = new Stack<>();
        stack.push(10);
        stack.push(20);
        stack.push(30);

        int top = stack.peek();   // 30 — not removed
        int popped = stack.pop(); // 30 — removed

        stack.reset(); // stack is now empty
    }
}

// JavaScript — Stack: Push, Pop, Peek, Reset

class Stack {
    constructor() {
        this.items = [];
    }

    // Push — add element to top
    push(item) {
        this.items.push(item);
    }

    // Pop — remove and return top element
    pop() {
        if (this.isEmpty())
            throw new Error('Stack is empty.');
        return this.items.pop();
    }

    // Peek — return top element without removing
    peek() {
        if (this.isEmpty())
            throw new Error('Stack is empty.');
        return this.items[this.items.length - 1];
    }

    // Reset — clear all elements
    reset() {
        this.items = [];
    }

    isEmpty() { return this.items.length === 0; }
    size() { return this.items.length; }
}

